from collections import Counter

class Solution(object):
    def numberOfPairs(self, nums1, nums2, k):
        # Good pair: nums1[i] % (nums2[j] * k) == 0
        # Equivalently: (nums2[j] * k) divides nums1[i]
        # Build freq map for nums2 * k values (only those that divide some nums1[i])
        cnt2 = Counter(v * k for v in nums2)
        ans = 0
        for v in nums1:
            # Enumerate all divisors of v
            d = 1
            while d * d <= v:
                if v % d == 0:
                    ans += cnt2[d]
                    if d != v // d:
                        ans += cnt2[v // d]
                d += 1
        return ans
